#!/usr/bin/env node

// WARNING: THIS FILE WAS GENERATED USING AN LLM

// This script will create a special `bricklink_id_to_lego.json` map file that helps link
// Bricklink part numbers to LEGO ones. It uses Rebrickable's API and thus requires a free
// account to retrieve the necessary API key. More information: https://rebrickable.com/api/

// To run this script:
//
// On POSIX systems:
//   REBRICKABLE_API_KEY=your_api_key node scripts/generate-bricklink-to-lego-using-api.js
//
// On Windows PowerShell:
//   $env:REBRICKABLE_API_KEY="your_api_key"
//   node scripts/generate-bricklink-to-lego-using-api.js

const fs = require("node:fs/promises");
const path = require("node:path");

const API_KEY = process.env.REBRICKABLE_API_KEY;
const OUTPUT_FILE = path.join(
  process.cwd(),
  "data",
  "bricklink_id_to_lego.json"
);

const BASE_URL = "https://rebrickable.com/api/v3/lego/parts/";
const PAGE_SIZE = 1000;
const REQUEST_DELAY_MS = Number(process.env.REBRICKABLE_REQUEST_DELAY_MS ?? 2000);
const MAX_RETRIES = Number(process.env.REBRICKABLE_MAX_RETRIES ?? 5);
const RETRY_BASE_DELAY_MS = Number(process.env.REBRICKABLE_RETRY_BASE_DELAY_MS ?? 10000);

if (!API_KEY) {
  console.error("Missing REBRICKABLE_API_KEY environment variable.");
  console.error("");
  console.error("Usage:");
  console.error("  REBRICKABLE_API_KEY=your_key node scripts/generate-bricklink-to-lego-using-api.js");
  process.exit(1);
}

function asStringArray(value) {
  if (!value) return [];

  if (Array.isArray(value)) {
    return value
      .map((item) => String(item).trim())
      .filter(Boolean);
  }

  return [String(value).trim()].filter(Boolean);
}

function getExternalIds(part, key) {
  return asStringArray(part.external_ids?.[key]);
}

function addMapping(mapping, bricklinkId, legoIds) {
  if (!bricklinkId || legoIds.length === 0) return;

  const filteredLegoIds = legoIds.filter(
    (legoId) => legoId.toLowerCase() !== bricklinkId.toLowerCase()
  );

  if (filteredLegoIds.length === 0) return;

  if (!mapping.has(bricklinkId)) {
    mapping.set(bricklinkId, new Set());
  }

  for (const legoId of filteredLegoIds) {
    mapping.get(bricklinkId).add(legoId);
  }
}

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function fetchJson(url, attempt = 1) {
  const response = await fetch(url, {
    headers: {
      Authorization: `key ${API_KEY}`,
      Accept: "application/json",
    },
  });

  if (response.status === 429 && attempt <= MAX_RETRIES) {
    const retryAfterHeader = response.headers.get("retry-after");
    const retryAfterSeconds = Number(retryAfterHeader);
    const retryDelayMs = Number.isFinite(retryAfterSeconds)
      ? retryAfterSeconds * 1000
      : RETRY_BASE_DELAY_MS * attempt;

    console.warn(
      `Rate limited by Rebrickable. Retrying in ${retryDelayMs}ms ` +
      `(attempt ${attempt}/${MAX_RETRIES})...`
    );

    await sleep(retryDelayMs);
    return fetchJson(url, attempt + 1);
  }

  if (response.status >= 500 && attempt <= MAX_RETRIES) {
    const retryDelayMs = RETRY_BASE_DELAY_MS * attempt;

    console.warn(
      `Rebrickable server error ${response.status}. Retrying in ${retryDelayMs}ms ` +
      `(attempt ${attempt}/${MAX_RETRIES})...`
    );

    await sleep(retryDelayMs);
    return fetchJson(url, attempt + 1);
  }

  if (!response.ok) {
    const body = await response.text();
    throw new Error(
      `Rebrickable request failed: ${response.status} ${response.statusText}\n${body}`
    );
  }

  return response.json();
}

async function main() {
  const mapping = new Map();

  let url = `${BASE_URL}?page_size=${PAGE_SIZE}`;
  let page = 1;
  let totalParts = 0;

  while (url) {
    console.log(`Fetching Rebrickable parts page ${page}...`);

    const data = await fetchJson(url);

    for (const part of data.results ?? []) {
      totalParts += 1;

      const bricklinkIds = getExternalIds(part, "BrickLink");

      // Only use official LEGO external IDs from Rebrickable.
      // Do not include Rebrickable's own part_num as a LEGO alternate.
      const legoIds = new Set(getExternalIds(part, "LEGO"));

      // This appends the Rebrickable part_num to the LEGO external IDs.
      // const legoIds = new Set([
      //   ...getExternalIds(part, "LEGO"),
      //   String(part.part_num).trim(),
      // ]);

      const cleanLegoIds = [...legoIds].filter(Boolean);

      for (const bricklinkId of bricklinkIds) {
        addMapping(mapping, bricklinkId, cleanLegoIds);
      }
    }

    url = data.next;
    page += 1;

    if (url && REQUEST_DELAY_MS > 0) {
      await sleep(REQUEST_DELAY_MS);
    }
  }

  const output = Object.fromEntries(
    [...mapping.entries()]
      .map(([bricklinkId, legoIds]) => [
        bricklinkId,
        [...legoIds]
          .filter((legoId) => legoId !== bricklinkId)
          .sort((a, b) =>
            a.localeCompare(b, undefined, { numeric: true })
          ),
      ])
      .filter(([, legoIds]) => legoIds.length > 0)
      .sort(([a], [b]) => a.localeCompare(b, undefined, { numeric: true }))
  );

  await fs.mkdir(path.dirname(OUTPUT_FILE), { recursive: true });
  await fs.writeFile(OUTPUT_FILE, `${JSON.stringify(output)}\n`, "utf8");

  console.log("");
  console.log(`Processed ${totalParts} Rebrickable parts.`);
  console.log(`Wrote ${Object.keys(output).length} BrickLink mappings.`);
  console.log(`Output: ${OUTPUT_FILE}`);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
